#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int sunny = 0, x;
        for (int i = 0; i < 7; ++i) {
            scanf("%d", &x);
            sunny += x; // x is 0 or 1
        }
        int rainy = 7 - sunny;
        if (sunny > rainy) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

